uint64 sys_brk(void) {
  uint64 addr; struct proc *p = myproc();
  argaddr(0, &addr);
  // brk(0) returns current program break — musl uses this as thread pointer!
  if (addr == 0) return p->brk;
  if (addr < p->brk || addr > TRAPFRAME) return p->brk;
  // Grow user memory from current sz if needed
  if (addr > p->sz) {
    int n = PGROUNDUP(addr) - PGROUNDUP(p->sz);
    if (n > 0 && growproc(n) < 0) return p->brk;
  }
  p->brk = addr;
  return addr;
}

