      uint64 bss_pa = walkaddr(pagetable, tls_va + tls_filesz);
      if (bss_pa) memset((void *)bss_pa, 0, tls_memsz - tls_filesz);
    }
  }
  if (elf.type == ET_DYN) main_phdr = exec_base + main_phdr;
  iunlockput(ip);
  ip = 0;
  // ---- 7. allocate user stack ----
  sz = PGROUNDUP(sz);
  p->brk = sz;    // 🚨 保存程序断点(初始化为加载段末尾)，musl 用它作为线程指针 tp
  uint64 sz1;
  if ((sz1 = uvmalloc(pagetable, sz, sz + 64 * PGSIZE, PTE_W)) == 0) goto bad;
  sz = sz1;
  uvmclear(pagetable, sz - 64 * PGSIZE);
  sp = sz;
  stackbase = sp - 63 * PGSIZE;

  // ====================================================================
  // 🚨 【核心修复：严格符合 RISC-V Linux ABI 的栈构造】 🚨
  // 原则：指针数组内部绝对紧密排列，消除所有 Padding 空洞！
  // ====================================================================
  ustack = (uint64 *)kalloc();
  if (ustack == 0) goto bad;
  memset(ustack, 0, PGSIZE);
  // (1) 压入 argv 字符串 (从高地址到低地址)
  for (argc = 0; argv[argc]; argc++) {
    if (argc >= MAXARG) goto bad;
    sp -= strlen(argv[argc]) + 1;
    sp &= ~0xF; // 字符串对齐
    if (sp < stackbase) goto bad;
    if (copyout(pagetable, sp, argv[argc], strlen(argv[argc]) + 1) < 0) goto bad;
    ustack[argc] = sp;
  }
  // (2) 压入 AT_RANDOM 数据 (16字节)
  sp -= 16;
  sp &= ~0xF;
  uint64 at_random_addr = sp;
  uint64 seed[2] = { 0x123456789ABCDEF0, 0xFEDCBA9876543210 };
  copyout(pagetable, at_random_addr, (char *)seed, 16);
  // (3) 计算指针块总大小，并对齐 sp
  uint64 ptr_block_size = 8 + (argc + 1) * 8 + 8 + 16 * 8;
  sp -= ptr_block_size;
  sp &= ~0xF;
  if (sp < stackbase) goto bad;
  uint64 cur_sp = sp;
  // (4) 压入 argc
  uint64 _argc = argc;
  copyout(pagetable, cur_sp, (char *)&_argc, 8);
  cur_sp += 8;
  uint64 argp = cur_sp;
   // (5) 压入 argv 指针数组 + NULL
  copyout(pagetable, cur_sp, (char *)ustack, argc * 8);
  cur_sp += argc * 8;
  uint64 zero = 0;
  copyout(pagetable, cur_sp, (char *)&zero, 8); // argv NULL
  cur_sp += 8;
  // (6) 压入 envp NULL
  copyout(pagetable, cur_sp, (char *)&zero, 8);
  cur_sp += 8;
  // (7) 压入 auxv 数组
  uint64 auxv[16];
  int auxc = 0;
  auxv[auxc++] = AT_PHDR;   auxv[auxc++] = main_phdr;
  auxv[auxc++] = AT_PHENT;  auxv[auxc++] = main_phent;
  auxv[auxc++] = AT_PHNUM;  auxv[auxc++] = main_phnum;
  auxv[auxc++] = AT_ENTRY;  auxv[auxc++] = main_entry;
  auxv[auxc++] = AT_BASE;   auxv[auxc++] = interp_base;
  auxv[auxc++] = AT_PAGESZ; auxv[auxc++] = PGSIZE;
  auxv[auxc++] = AT_RANDOM; auxv[auxc++] = at_random_addr;
  auxv[auxc++] = AT_NULL;   auxv[auxc++] = 0;
  copyout(pagetable, cur_sp, (char *)auxv, 16 * 8);
  // ---- save process name ----
  sp = cur_sp;  // sp points to argc
  for (last = s = path; *s; s++) if (*s == '/') last = s + 1;
  safestrcpy(p->name, last, sizeof(p->name));
  // ====================================================================
  // 🚨 【核心修复：延迟提交 Delayed Commit】 🚨
  // ====================================================================

  asm volatile("fence.i");

  oldpagetable = p->pagetable;
  uint64 oldsz = p->sz;

  p->pagetable = pagetable;
  p->sz = sz;

  p->trapframe->epc = has_interp ? interp_entry : (exec_base + elf.entry);
  p->trapframe->sp  = sp;
  p->trapframe->ra  = 0;
  // Point tp into stack area (mapped, writable) so early TLS access doesn't fault.
  // musl __init_tp will overwrite tp with the real TLS pointer.
  p->trapframe->tp = has_tls ? ((elf.type == ET_DYN) ? exec_base + tls_vaddr : tls_vaddr) : (sp - 8);
  p->trapframe->a1  = argp;

  proc_freepagetable(oldpagetable, oldsz);
  if (ustack) kfree((char *)ustack);
  return 0;

bad:
  if (interp_ip) iunlockput(interp_ip); 
  if (ip) iunlockput(ip);

  if (pagetable) {
    proc_freepagetable(pagetable, sz); 
  }

  if (ustack) kfree((char *)ustack);

  return -1;
}

static int
loadseg(pagetable_t pagetable, uint64 va, struct inode *ip, uint offset, uint sz)
{
  uint i;
  uint64 pa;
  for (i = 0; i < sz; ) {
    // 🚨 处理非页对齐 VA：先降到页基地址，加上页内偏移，每次只读到一个页边界
    uint page_off = (va + i) & (PGSIZE - 1);
    pa = walkaddr(pagetable, (va + i) - page_off);
    if (pa == 0) panic("loadseg");
    uint n = PGSIZE - page_off;
    if (n > sz - i) n = sz - i;
    if (readi(ip, 0, (uint64)(pa + page_off), offset + i, n) != n) return -1;
    i += n;
  }
  return 0;
}

// On-disk file system format.
// Both the kernel and user programs use this header file.

#define ROOTINO 1    // root i-number
#define BSIZE   1024 // block size

// Disk layout:
// [ boot block | super block | log | inode blocks |
//                                          free bit map | data blocks]
//
// mkfs computes the super block and builds an initial file system. The
// super block describes the disk layout:
struct superblock {
  uint magic;      // Must be FSMAGIC
  uint size;       // Size of file system image (blocks)
  uint nblocks;    // Number of data blocks
  uint ninodes;    // Number of inodes.
  uint nlog;       // Number of log blocks
  uint logstart;   // Block number of first log block
  uint inodestart; // Block number of first inode block
  uint bmapstart;  // Block number of first free map block
};
// ext4 superblock — 位于 block 0 偏移 1024 字节处
// 关键字段的磁盘偏移用注释标注
struct ext4_superblock {
  uint inodes_count;         // 0x00: Total inodes
  uint blocks_count;         // 0x04: Total blocks (low 32)
  uint r_blocks_count;       // 0x08: Reserved blocks
  uint free_blocks_count;    // 0x0C: Free blocks
  uint free_inodes_count;    // 0x10: Free inodes
  uint first_data_block;     // 0x14: First data block (=0 for >=1KB block)
  uint log_block_size;       // 0x18: Block size = 1024 << this
  uint log_cluster_size;     // 0x1C: Cluster size (bigalloc)
  uint blocks_per_group;     // 0x20: Blocks per group
  uint obso_frags_per_group; // 0x24
  uint inodes_per_group;     // 0x28: Inodes per group
  uint mtime;                // 0x2C
  uint wtime;                // 0x30
  uchar _pad1[4];            // 0x34
  ushort magic;              // 0x38: Magic = 0xEF53
  ushort state;              // 0x3A
  ushort errors;             // 0x3C
  ushort minor_rev_level;    // 0x3E
  uchar _pad2[22];           // 0x40–0x55
  ushort inode_size;         // 0x58: Size of inode structure
  uchar _pad3[38];           // 0x5A–0x7F
} __attribute__((packed));

// ext4 块组描述符 — 64 字节版本（64bit 特性启用时）
// 前 32 字节与 32 字节版本相同，后 32 字节是 64bit 扩展
struct ext4_group_desc {
  uint  block_bitmap;          // 0x00: Blocks bitmap block (lo)
  uint  inode_bitmap;          // 0x04: Inodes bitmap block (lo)
  uint  inode_table;           // 0x08: Inodes table start block (lo)
  uchar free_blocks_count[2];  // 0x0C
  uchar free_inodes_count[2];  // 0x0E
  uchar used_dirs_count[2];    // 0x10
  uchar flags[2];              // 0x12
  uchar exclude_bitmap[4];     // 0x14
  uchar block_bitmap_csum[2];  // 0x18
  uchar inode_bitmap_csum[2];  // 0x1A
  uchar itable_unused[2];      // 0x1C
  uchar checksum[2];           // 0x1E
  // 64bit 扩展字段（后 32 字节）
  uint  block_bitmap_hi;       // 0x20
  uint  inode_bitmap_hi;       // 0x24
  uint  inode_table_hi;        // 0x28
  uchar _pad_hi[20];           // 0x2C–0x3F
} __attribute__((packed));

// ext4 磁盘 inode — 偏移必须精确匹配 ext4 规范
// 关键：i_block[60] 在偏移 0x28，size_hi 在偏移 0x6C
struct ext4_inode {
  uchar mode[2];             // 0x00: File mode
  uchar uid[2];              // 0x02: Owner UID (low 16)
  uchar size_lo[4];          // 0x04: Size (low 32)
  uchar atime[4];            // 0x08: Access time
  uchar ctime[4];            // 0x0C: Creation time
  uchar mtime[4];            // 0x10: Modification time
  uchar dtime[4];            // 0x14: Deletion time
  uchar gid[2];              // 0x18: Group ID (low 16)
  uchar links_count[2];      // 0x1A: Hard links count
  uchar blocks_lo[4];        // 0x1C: Block count (low 32)
  uchar flags[4];            // 0x20: Inode flags
  uchar osd1[4];             // 0x24: OS dependent 1
  uchar block[60];           // 0x28: Extent tree root (i_block)
  uchar generation[4];       // 0x64: File version
  uchar file_acl_lo[4];      // 0x68: File ACL (low 32)
  uchar size_hi[4];          // 0x6C: Size (high 32)
} __attribute__((packed));

// ext4 extent 树节点头
struct ext4_extent_header {
  uchar magic[2];            // 0xF30A
  uchar entries[2];          // 当前节点中的条目数
  uchar max[2];              // 最大条目容量
  uchar depth[2];            // 树深度（0 = 叶子）
  uchar generation[4];       // 代数
} __attribute__((packed));

// ext4 extent 叶子条目
struct ext4_extent {
  uchar block[4];            // 第一个逻辑块号
  uchar len[2];              // 块数（低 15 位有效）
  uchar start_hi[2];         // 物理块号高 16 位
  uchar start_lo[4];         // 物理块号低 32 位
} __attribute__((packed));

// ext4 extent 内部节点索引
struct ext4_extent_idx {
  uchar block[4];            // 逻辑块号
  uchar leaf_lo[4];          // 下层节点物理块号低 32 位
  uchar leaf_hi[2];          // 下层节点物理块号高 16 位
  uchar _unused[2];          // 填充到 12 字节
} __attribute__((packed));

struct ext4_dir_entry{
  uint inode;           // Inode number
  ushort rec_len;       // Directory entry length
  uchar name_len;       // Name length
  uchar file_type;      // File type
  char name[];          // File name, up to EXT4_NAME_LEN=255 chars
} __attribute__((packed));

#define FSMAGIC 0x10203040

#define NDIRECT   12
#define NINDIRECT (BSIZE / sizeof(uint))
#define MAXFILE   (NDIRECT + NINDIRECT)


//define ext4 constants
#define EXT4_SUPER_MAGIC 0xEF53
#define EXT4_EXT_MAGIC 0xF30A
// ext4 file types
#define EXT4_FT_UNKNOWN 0
#define EXT4_FT_REG_FILE 1
#define EXT4_FT_DIR 2
#define EXT4_FT_CHRDEV 3
#define EXT4_FT_BLKDEV 4
#define EXT4_FT_FIFO 5
#define EXT4_FT_SOCK 6
#define EXT4_FT_SYMLINK 7

// Inodes per block.
#define EXT4_S_IFREG   0x8000
#define EXT4_S_IFDIR   0x4000
#define EXT4_S_IFLNK   0xA000
// On-disk inode structure
struct dinode {
  short type;              // File type
  short major;             // Major device number (T_DEVICE only)
  short minor;             // Minor device number (T_DEVICE only)
  short nlink;             // Number of links to inode in file system
  uint size;               // Size of file (bytes)
  uint addrs[NDIRECT + 1]; // Data block addresses
};

// Inodes per block.
#define IPB (BSIZE / sizeof(struct dinode))

// Block containing inode i
#define IBLOCK(i, sb) ((i) / IPB + sb.inodestart)

// Bitmap bits per block
#define BPB (BSIZE * 8)

// Block of free map containing bit for block b
#define BBLOCK(b, sb) ((b) / BPB + sb.bmapstart)

// Directory is a file containing a sequence of dirent structures.
// Increased to 255 for ext4 long filenames (was 14 for xv6)
#define DIRSIZ 255

// The name field may have DIRSIZ characters and not end in a NUL
// character.
struct dirent {
  ushort inum;
  char name[DIRSIZ] __attribute__((nonstring));
};
struct linux_dirent64 {
  uint64 d_ino;    //  inode number
  uint64  d_off;    //  offset to the next dirent
  uint16 d_reclen; //  length of this record
  uint8  d_type;   //  file type
  char   d_name[]; //  filename (null-terminated)
};

// File system implementation.  Five layers:
//   + Blocks: allocator for raw disk blocks.
//   + Log: crash recovery for multi-step updates.
//   + Files: inode allocator, reading, writing, metadata.
//   + Directories: inode with special contents (list of other inodes!)
//   + Names: paths like /usr/rtm/xv6/fs.c for convenient naming.
//
// This file contains the low-level file system manipulation
// routines.  The (higher-level) system call implementations
// are in sysfile.c.

#include "types.h"
#include "riscv.h"
#include "defs.h"
#include "param.h"
#include "stat.h"
#include "spinlock.h"
#include "proc.h"
#include "sleeplock.h"
#include "fs.h"
#include "buf.h"
#include "file.h"

#define min(a, b) ((a) < (b) ? (a) : (b))
#define EXT4_ROOT_INO 2      // ext4 根目录 inode 号
// there should be one superblock per disk device, but we run with
// only one device
struct superblock sb;

// ---- little-endian 辅助函数 ----
static inline uint le32_to_host(const uchar *p) {
  return p[0] | (p[1] << 8) | (p[2] << 16) | (p[3] << 24);
}
static inline ushort le16_to_host(const uchar *p) {
  return p[0] | (p[1] << 8);
}

// ---- ext4 全局状态 ----
struct ext4_superblock ext4_sb;          // ext4 超级块（定义在此，供其他文件 extern 引用）
struct ext4_group_desc *ext4_gdt; // 块组描述符表（内存拷贝）
uint ext4_inodes_per_group;       // 每个块组的 inode 数
uint ext4_blocks_per_group;       // 每个块组的块数
uint ext4_block_size;             // ext4 逻辑块大小（字节）
uint ext4_sectors_per_block;      // 每个 ext4 块 = 多少个 1024B 扇区
int  ext4_fs;                            // 1 = 当前挂载的是 ext4，0 = xv6 fs（log.c 需要 extern）

// 前置声明
static struct inode *iget(uint dev, uint inum);

// Read the super block — 同时支持 ext4 和 xv6 原始格式
static void
readsb(int dev, struct superblock *sb)
{
  struct buf *bp;
  uchar *raw;

  // ext4 superblock 始终在磁盘字节偏移 1024 处
  // 对于 BSIZE=1024，即扇区 1 偏移 0
  bp = bread(dev, 1);
  raw = bp->data;

  ushort magic = le16_to_host(raw + 0x38);

  if (magic == EXT4_SUPER_MAGIC) {
    printf("fs: ext4 filesystem detected\n");

    // 计算 ext4 块大小和扇区转换比
    uint log_bsize = le32_to_host(raw + 0x18);
    ext4_block_size = 1024 << log_bsize;
    ext4_sectors_per_block = ext4_block_size / BSIZE;
    if (ext4_block_size % BSIZE != 0)
      panic("ext4: block size not multiple of BSIZE");

    // 解析超级块关键字段
    ext4_sb.inodes_count       = le32_to_host(raw + 0x00);
    ext4_sb.blocks_count       = le32_to_host(raw + 0x04);
    ext4_sb.first_data_block   = le32_to_host(raw + 0x14);
    ext4_sb.log_block_size     = log_bsize;
    ext4_sb.blocks_per_group   = le32_to_host(raw + 0x20);
    ext4_sb.inode_size         = le16_to_host(raw + 0x58);
    ext4_sb.magic              = magic;

    ext4_inodes_per_group = le32_to_host(raw + 0x28);
    ext4_blocks_per_group = ext4_sb.blocks_per_group;
    ext4_fs = 1;

    printf("ext4: %d inodes, %d blocks, %d blocks/grp, inode %dB, "
           "blk %dB (×%d sectors)\n",
           ext4_sb.inodes_count, ext4_sb.blocks_count,
           ext4_blocks_per_group, ext4_sb.inode_size,
           ext4_block_size, ext4_sectors_per_block);

    // 填充兼容字段（只读用）
    sb->magic      = EXT4_SUPER_MAGIC;   // 借这个字段标记 ext4
    sb->size       = ext4_sb.blocks_count;
    sb->ninodes    = ext4_sb.inodes_count;
    sb->nlog       = 0;
    sb->inodestart = 0;
    sb->bmapstart  = 0;

  } else if (magic == FSMAGIC) {
    printf("fs: xv6 filesystem detected\n");
    memmove(sb, bp->data, sizeof(*sb));
    ext4_fs = 0;
  } else {
    printf("readsb: unknown filesystem magic 0x%x\n", magic);
    panic("readsb bad magic");
  }

  brelse(bp);
}

// Init fs
void
fsinit(int dev)
{
  readsb(dev, &sb);

  if (ext4_fs) {
    // 计算块组描述符表的大小和位置
    uint ngroups = (ext4_sb.blocks_count - ext4_sb.first_data_block
                    + ext4_blocks_per_group - 1) / ext4_blocks_per_group;
    uint gdt_bytes = ngroups * sizeof(struct ext4_group_desc);
    uint gdt_blocks = (gdt_bytes + BSIZE - 1) / BSIZE;

    ext4_gdt = (struct ext4_group_desc *)kalloc();
    if (ext4_gdt == 0)
      panic("fsinit: no memory for ext4 group descriptors");

    // GDT starts after the superblock block: (first_data_block + 1) * sectors_per_block
    uint gdt_start_sector = (ext4_sb.first_data_block + 1) * ext4_sectors_per_block;
    uchar *dst = (uchar *)ext4_gdt;
    for (uint i = 0; i < gdt_blocks; i++) {
      struct buf *bp = bread(dev, gdt_start_sector + i);
      uint copy = gdt_bytes - i * BSIZE;
      if (copy > BSIZE) copy = BSIZE;
      memmove(dst, bp->data, copy);
      dst += BSIZE;
      brelse(bp);
    }

    printf("ext4: loaded %d GDT blocks (%d groups)\n", gdt_blocks, ngroups);

    struct inode *ip = iget(dev, EXT4_ROOT_INO);
    ilock(ip);
    printf("ext4: root inode %d, type=%d, size=%d\n",
           EXT4_ROOT_INO, ip->type, ip->size);
    iunlock(ip);
    iput(ip);

    return;
  }

  if (sb.magic != FSMAGIC)
    panic("invalid filesystem");

  initlog(dev, &sb);
  ireclaim(dev);
}

// ---- ext4 磁盘 inode 读取 ----
// 从磁盘读取 ext4 inode 并填充到 xv6 的 struct inode
// 调用者必须已持有 ip->lock
void
ext4_read_inode(struct inode *ip)
{
  uint inode_no = ip->inum;
  uint dev = ip->dev;

  // 1. 定位 inode 所在的块组
  uint group = (inode_no - 1) / ext4_inodes_per_group;
  if (group >= (ext4_sb.blocks_count / ext4_blocks_per_group + 1)) {
    printf("ext4_read_inode: inode %d group %d out of range\n", inode_no, group);
    panic("ext4_read_inode");
  }

  // 2. 从块组描述符获取 inode table 起始 ext4 块号
  uint table_block = ext4_gdt[group].inode_table;

  // 3. 计算 inode 在 table 中的字节偏移，转为扇区
  uint index = (inode_no - 1) % ext4_inodes_per_group;
  uint offset = index * ext4_sb.inode_size;           // inode table 内字节偏移
  uint ext4_blk_ofs = offset / ext4_block_size;        // ext4 块内偏移
  uint byte_in_blk  = offset % ext4_block_size;        // ext4 块内字节偏移
  uint sector = (table_block + ext4_blk_ofs) * ext4_sectors_per_block
              + byte_in_blk / BSIZE;
  uint block_off = byte_in_blk % BSIZE;

  // 4. 读盘并提取 ext4_inode
  struct buf *bp = bread(dev, sector);
  struct ext4_inode *raw = (struct ext4_inode *)(bp->data + block_off);

  // 5. 解析字段并填充到 xv6 struct inode
  ushort mode = le16_to_host(raw->mode);
  switch (mode & 0xF000) {
  case EXT4_S_IFREG:  ip->type = T_FILE;   break;
  case EXT4_S_IFDIR:  ip->type = T_DIR;    break;
  case EXT4_S_IFLNK:  ip->type = T_FILE;   break;  // 符号链接先当普通文件
  default:            ip->type = T_DEVICE; break;
  }
  ip->major = 0;
  ip->minor = 0;
  ip->nlink = le16_to_host(raw->links_count);

  uint64 size_lo = le32_to_host(raw->size_lo);
  uint64 size_hi = le32_to_host(raw->size_hi);
  ip->size = (size_hi << 32) | size_lo;

  ip->valid = 1;
  brelse(bp);
}
// ---- ext4 extent 树查找 ----
// lbn: xv6 逻辑块号（1024 字节粒度）
// 返回: 物理扇区号，0 表示未找到
static uint
ext4_bmap(struct inode *ip, uint lbn)
{
  uint ext4_lbn = lbn / ext4_sectors_per_block;
  uint ino = ip->inum;
  uint dev = ip->dev;
  uint group = (ino - 1) / ext4_inodes_per_group;
  uint table_blk = ext4_gdt[group].inode_table;
  uint index = (ino - 1) % ext4_inodes_per_group;
  uint off = index * ext4_sb.inode_size;
  uint ext4_blk_ofs = off / ext4_block_size;
  uint byte_in_blk  = off % ext4_block_size;
  uint sector_inode = (table_blk + ext4_blk_ofs) * ext4_sectors_per_block
                    + byte_in_blk / BSIZE;
  uint blk_off = byte_in_blk % BSIZE;
  struct buf *bp = bread(dev, sector_inode);
  struct ext4_inode *raw = (struct ext4_inode *)(bp->data + blk_off);
  struct ext4_extent_header *eh = (struct ext4_extent_header *)raw->block;
  ushort magic = le16_to_host(eh->magic);
  ushort depth = le16_to_host(eh->depth);
  ushort entries = le16_to_host(eh->entries);
  if (magic != EXT4_EXT_MAGIC) { brelse(bp); return 0; }
  uint ext4_pblk = 0;
  while (1) {
