static void run_test_script(char *script_path, char *busybox_path, char *group_name) {
  struct inode *ip = namei(busybox_path);
  if (!ip) {
    return;
  }

  // 🚨 诊断：读取 ELF 头，检查是静态还是动态链接
  struct elfhdr elf;
  ilock(ip);
  if (readi(ip, 0, (uint64)&elf, 0, sizeof(elf)) == sizeof(elf)) {

    // 检查是否有 PT_INTERP（动态链接器）
    for (int i = 0, off = elf.phoff; i < elf.phnum; i++, off += elf.phentsize) {
      struct proghdr ph;
      if (readi(ip, 0, (uint64)&ph, off, sizeof(ph)) == sizeof(ph)) {
        if (ph.type == 3) { // PT_INTERP
          char interp[256] = {0};
          readi(ip, 0, (uint64)interp, ph.off, ph.filesz < 255 ? ph.filesz : 255);

        }
      }
    }
  }
  iunlockput(ip);

  // 检查脚本是否存在
  ip = namei(script_path);
  if (!ip) {
    return;
  }
  iput(ip);

  printf("#### OS COMP TEST GROUP START %s ####\n", group_name);

  // Set contest_path + extra argv so forkret will kexec with full argv.
  // The child starts from forkret(), not from the kfork return point!
  safestrcpy(myproc()->contest_path, busybox_path, sizeof(myproc()->contest_path));
  safestrcpy(myproc()->contest_argv1, "echo", sizeof(myproc()->contest_argv1));
  safestrcpy(myproc()->contest_argv2, script_path, sizeof(myproc()->contest_argv2));
  int pid = kfork();
  myproc()->contest_path[0] = 0;
  myproc()->contest_argv1[0] = 0;
  myproc()->contest_argv2[0] = 0;
  if (pid < 0) {
    printf("#### OS COMP TEST GROUP END %s ####\n", group_name);
    return;
  }
  kwait(0);

  printf("#### OS COMP TEST GROUP END %s ####\n", group_name);
}
