// ext4 global state from fs.c
extern struct ext4_superblock ext4_sb;
extern struct ext4_group_desc *ext4_gdt;
extern uint ext4_inodes_per_group;
extern uint ext4_blocks_per_group;
extern uint ext4_block_size;
extern uint ext4_sectors_per_block;

// LE read helpers (fs.c has them as static inline; duplicate here)
static inline uint le32_to_host(const uchar *p) {
  return p[0] | (p[1] << 8) | (p[2] << 16) | (p[3] << 24);
}
static inline ushort le16_to_host(const uchar *p) {
  return p[0] | (p[1] << 8);
}

// Helper: write 16-bit LE value to byte array
static inline void le16_store(uchar *p, ushort v) {
  p[0] = v & 0xFF; p[1] = (v >> 8) & 0xFF;
}
// Helper: write 32-bit LE value to byte array
static inline void le32_store(uchar *p, uint v) {
  p[0] = v & 0xFF; p[1] = (v >> 8) & 0xFF;
  p[2] = (v >> 16) & 0xFF; p[3] = (v >> 24) & 0xFF;
}

// Max disk sectors (64MB / 1024 bytes per sector)
#define EXT4_MAX_SECTOR 65536

// Locate the disk sector and offset for a given ext4 inode number.
// Returns the buffer (bread) with bp_data pointing to the raw ext4_inode.
static struct buf *
ext4_read_inode_buf(uint dev, uint ino, struct ext4_inode **out)
{
  uint group = (ino - 1) / ext4_inodes_per_group;
  uint table_block = ext4_gdt[group].inode_table;
  uint index = (ino - 1) % ext4_inodes_per_group;
  uint offset = index * ext4_sb.inode_size;
  uint ext4_blk_ofs = offset / ext4_block_size;
  uint byte_in_blk  = offset % ext4_block_size;
  uint sector = (table_block + ext4_blk_ofs) * ext4_sectors_per_block
              + byte_in_blk / BSIZE;
  uint block_off = byte_in_blk % BSIZE;

  if (sector >= EXT4_MAX_SECTOR) {
    panic("ext4_read_inode_buf: sector out of range");
  }
  struct buf *bp = bread(dev, sector);
  *out = (struct ext4_inode *)(bp->data + block_off);
  return bp;
}

// Allocate a free block on ext4 filesystem. Returns ext4 block number, 0 = fail.
uint
ext4_balloc(uint dev)
{
  struct ext4_superblock *sb = &ext4_sb;
  uint ngroups = (sb->blocks_count - sb->first_data_block
                  + ext4_blocks_per_group - 1) / ext4_blocks_per_group;

  uint free = 0;
  for (uint g = 0; g < ngroups; g++) {
    free = le16_to_host(ext4_gdt[g].free_blocks_count);
    if (free == 0) continue;

    uint bmap_blk = ext4_gdt[g].block_bitmap;
    uint start = g * ext4_blocks_per_group + sb->first_data_block;
    uint end = start + ext4_blocks_per_group;
    if (end > sb->blocks_count) end = sb->blocks_count;

    uint bits_per_sector = BSIZE * 8;
    for (uint bs = 0; bs < ext4_sectors_per_block; bs++) {
      struct buf *bp = bread(dev, bmap_blk * ext4_sectors_per_block + bs);
      for (uint bi = 0; bi < bits_per_sector; bi++) {
        uint blk_idx = bi + bs * bits_per_sector; // absolute bit in this group
        if (start + blk_idx >= end) break;
        if ((bp->data[bi / 8] & (1 << (bi % 8))) == 0) {
          bp->data[bi / 8] |= (1 << (bi % 8));
          bwrite(bp);
          brelse(bp);
          uint blk = start + blk_idx;
          // Bounds check against total disk blocks
          if (blk >= sb->blocks_count) {
            printf("ext4_balloc: invalid block %d >= %d\n", blk, sb->blocks_count);
            return 0;
          }
          for (uint si = 0; si < ext4_sectors_per_block; si++) {
            struct buf *zb = bread(dev, blk * ext4_sectors_per_block + si);
            memset(zb->data, 0, BSIZE);
            bwrite(zb);
            brelse(zb);
          }
          le16_store(ext4_gdt[g].free_blocks_count, free - 1);
          return blk;
        }
      }
      brelse(bp);
    }
  }
  printf("ext4_balloc: out of blocks\n");
  return 0;
}

// Write back ext4 inode to disk.
void
ext4_iupdate(struct inode *ip)
{
  struct ext4_inode *raw;
  struct buf *bp = ext4_read_inode_buf(ip->dev, ip->inum, &raw);

  // Mode
  ushort mode = 0;
  switch (ip->type) {
  case T_DIR:  mode = 0x41FF; break; // 040777
  case T_FILE: mode = 0x81A4; break; // 0100664
  default:     mode = 0x81A4; break;
  }
  le16_store(raw->mode, mode);
  // UID / GID = 0
  le16_store(raw->uid, 0);
  le16_store(raw->gid, 0);
  // Size
  le32_store(raw->size_lo, ip->size & 0xFFFFFFFF);
  le32_store(raw->size_hi, ((uint64)ip->size >> 32) & 0xFFFFFFFF);
  // Links
  le16_store(raw->links_count, ip->nlink);
  // Flags: ensure EXT4_EXTENTS_FL (0x80000) is set so extent tree is used
  uint flags = le32_to_host(raw->flags);
  flags |= 0x80000; // EXT4_EXTENTS_FL
  le32_store(raw->flags, flags);
  // Blocks count (in 512-byte sectors) - approximate
  le32_store(raw->blocks_lo, (ip->size + 511) / 512);

  bwrite(bp);
  brelse(bp);
}

