//
// driver for qemu's virtio disk device.
// uses qemu's mmio interface to virtio.
//

#include "types.h"
#include "riscv.h"
#include "defs.h"
#include "param.h"
#include "memlayout.h"
#include "spinlock.h"
#include "sleeplock.h"
#include "fs.h"
#include "buf.h"
#include "virtio.h"

// MEMFS mode: filesystem image embedded in kernel binary, no virtio needed
#ifdef MEMFS
extern char _binary_testfs_img_start[];
extern char _binary_testfs_img_size[];

void virtio_disk_init(void) {}
void virtio_disk_intr() {}

void virtio_disk_rw(struct buf *b, int write) {
  uint64 off = (uint64)b->blockno * BSIZE;
  if (off + BSIZE > (uint64)_binary_testfs_img_size)
    panic("disk rw out of bounds");
  char *p = _binary_testfs_img_start + off;
  if (write) memmove(p, b->data, BSIZE);
  else       memmove(b->data, p, BSIZE);
}
#else

#define R(r) ((volatile uint32 *)(VIRTIO0 + (r)))

static struct disk {
  // Legacy mode requires contiguous physical memory for all three
  // queue parts, with used ring on a page boundary.  A static
  // 2-page aligned array guarantees this.
  char pages[2 * PGSIZE] __attribute__((aligned(PGSIZE)));
  struct virtq_desc *desc;
  struct virtq_avail *avail;
  struct virtq_used *used;
  char free[NUM];
  uint16 used_idx;
  int legacy;   // 1 = legacy (pre-v1.0) mmio transport
  struct { struct buf *b; char status; } info[NUM];
  struct virtio_blk_req ops[NUM];
  struct spinlock vdisk_lock;
} disk;

void
virtio_disk_init(void)
{
  uint32 status = 0;

  initlock(&disk.vdisk_lock, "virtio_disk");

  if (*R(VIRTIO_MMIO_MAGIC_VALUE) != 0x74726976 ||
      (*R(VIRTIO_MMIO_VERSION) != 2 && *R(VIRTIO_MMIO_VERSION) != 1) ||
      *R(VIRTIO_MMIO_DEVICE_ID) != 2 ||
      *R(VIRTIO_MMIO_VENDOR_ID) != 0x554d4551) {
    panic("could not find virtio disk");
  }

  *R(VIRTIO_MMIO_STATUS) = status;
  status |= VIRTIO_CONFIG_S_ACKNOWLEDGE;
  *R(VIRTIO_MMIO_STATUS) = status;
  status |= VIRTIO_CONFIG_S_DRIVER;
  *R(VIRTIO_MMIO_STATUS) = status;

  // --- feature negotiation (legacy + modern) ---
  *R(VIRTIO_MMIO_DEVICE_FEATURES_SEL) = 0;
  uint32 flo = *R(VIRTIO_MMIO_DEVICE_FEATURES);
  *R(VIRTIO_MMIO_DEVICE_FEATURES_SEL) = 1;
  uint32 fhi = *R(VIRTIO_MMIO_DEVICE_FEATURES);
  uint64 features = ((uint64)fhi << 32) | flo;

  // legacy mode: device only offers 32-bit features (fhi == 0)
  disk.legacy = (fhi == 0);

  // negotiate: clear features we don't support
  features &= ~(1ULL << VIRTIO_BLK_F_RO);
  features &= ~(1ULL << VIRTIO_BLK_F_SCSI);
  features &= ~(1ULL << VIRTIO_BLK_F_CONFIG_WCE);
  features &= ~(1ULL << VIRTIO_BLK_F_MQ);
  features &= ~(1ULL << VIRTIO_F_ANY_LAYOUT);
  features &= ~(1ULL << VIRTIO_RING_F_EVENT_IDX);
  features &= ~(1ULL << VIRTIO_RING_F_INDIRECT_DESC);
  // Bits 24+ are transport features (e.g. VIRTIO_F_NOTIFICATION_DATA).
  // They are only valid when VERSION_1 is negotiated. If the device
  // reports them without VERSION_1 (legacy mode), we must clear them,
  // otherwise QEMU may expect notification-data-aware behaviour.
  if (!disk.legacy) {
    features |= (1ULL << 32);  // VIRTIO_F_VERSION_1 (modern)
  }
  // Always clear transport feature bits (24+) the driver doesn't support

  // write driver features
  *R(VIRTIO_MMIO_DRIVER_FEATURES_SEL) = 0;
  *R(VIRTIO_MMIO_DRIVER_FEATURES) = (uint32)features;
  if (!disk.legacy) {
    *R(VIRTIO_MMIO_DRIVER_FEATURES_SEL) = 1;
    *R(VIRTIO_MMIO_DRIVER_FEATURES) = (uint32)(features >> 32);
  }

  status |= VIRTIO_CONFIG_S_FEATURES_OK;
  *R(VIRTIO_MMIO_STATUS) = status;
  status = *R(VIRTIO_MMIO_STATUS);
  if (!(status & VIRTIO_CONFIG_S_FEATURES_OK))
    panic("virtio disk FEATURES_OK unset");

  // --- queue setup ---
  *R(VIRTIO_MMIO_QUEUE_SEL) = 0;
  if (*R(VIRTIO_MMIO_QUEUE_READY))
    panic("virtio disk should not be ready");

  uint32 max = *R(VIRTIO_MMIO_QUEUE_NUM_MAX);
  if (max == 0) panic("virtio disk has no queue 0");
  if (max < NUM) panic("virtio disk max queue too short");

  if (disk.legacy) {
    // === LEGACY (pre-v1.0) queue setup via QUEUE_PFN ===
    // Use static 2-page aligned array — guarantees contiguity.
    // Layout: Page0=desc+avail, Page1=used (page-aligned).
    memset(disk.pages, 0, sizeof(disk.pages));
    disk.desc = (struct virtq_desc *)disk.pages;
    disk.avail = (struct virtq_avail *)(disk.pages + NUM * sizeof(struct virtq_desc));
    disk.used = (struct virtq_used *)(disk.pages + PGSIZE);

    *R(VIRTIO_MMIO_GUEST_PAGE_SIZE) = PGSIZE;
    *R(VIRTIO_MMIO_QUEUE_NUM) = NUM;
    *R(VIRTIO_MMIO_QUEUE_PFN) = ((uint64)disk.pages) >> 12;
  } else {
    // === MODERN (v1.0+) queue setup via descriptor registers ===
    disk.desc = kalloc();
    disk.avail = kalloc();
    disk.used = kalloc();
    if (!disk.desc || !disk.avail || !disk.used) panic("virtio disk kalloc");
    memset(disk.desc, 0, PGSIZE);
    memset(disk.avail, 0, PGSIZE);
    memset(disk.used, 0, PGSIZE);

    *R(VIRTIO_MMIO_QUEUE_NUM) = NUM;

    *R(VIRTIO_MMIO_QUEUE_DESC_LOW) = (uint64)disk.desc;
    *R(VIRTIO_MMIO_QUEUE_DESC_HIGH) = (uint64)disk.desc >> 32;
    *R(VIRTIO_MMIO_DRIVER_DESC_LOW) = (uint64)disk.avail;
    *R(VIRTIO_MMIO_DRIVER_DESC_HIGH) = (uint64)disk.avail >> 32;
