    if (ip->type == T_DIR && accmode != O_RDONLY) {
      iunlockput(ip); end_op(); return -1;
    }
  }

  if (ip->type == T_DEVICE && (ip->major < 0 || ip->major >= NDEV)) {
    iunlockput(ip); end_op(); return -1;
  }

  if ((f = filealloc()) == 0 || (fd = fdalloc(f)) < 0) {
    if (f) fileclose(f);
    iunlockput(ip); end_op(); return -1;
  }

  if (ip->type == T_DEVICE) {
    f->type = FD_DEVICE;
    f->major = ip->major;
  } else {
    f->type = FD_INODE;
    f->off = 0;
  }
  f->ip = ip;
  f->readable = !(omode & O_WRONLY);
  f->writable = (omode & O_WRONLY) || (omode & O_RDWR);

  if ((omode & O_TRUNC) && ip->type == T_FILE)
    itrunc(ip);

  iunlock(ip);
  end_op();
  return fd;
}

// mmap(addr, length, prot, flags, fd, offset)
#define PROT_READ   0x1
#define PROT_WRITE  0x2
#define PROT_EXEC   0x4
#define MAP_PRIVATE 0x02
#define MAP_ANON    0x20

uint64
sys_mmap(void)
{
  uint64 addr, length, offset;
  int prot, flags, fd;
  struct file *f = 0;
  struct proc *p = myproc();

  argaddr(0, &addr);
  argaddr(1, &length);
  argint(2, &prot);
  argint(3, &flags);
  argint(4, &fd);
  argaddr(5, &offset);

  uint64 map_sz = PGROUNDUP(length);
  uint64 old_sz = p->sz;

  if (old_sz + map_sz > TRAPFRAME)
    return -1;

  // Grow user memory
  p->sz = old_sz + map_sz;

  int did_file_map = 0;
  if (!(flags & MAP_ANON) && fd >= 0 && fd < NOFILE) {
    f = p->ofile[fd];
    if (f && f->type == FD_INODE && f->readable) {
      ilock(f->ip);
      uint64 left = length;
      uint64 file_off = offset;
      uint64 mem_off = old_sz;
      while (left > 0) {
        uint chunk = PGSIZE;
        if (chunk > left) chunk = left;

        char *pa = kalloc();
        if (pa == 0) { iunlock(f->ip); return -1; }
        memset(pa, 0, PGSIZE);
        if (mappages(p->pagetable, mem_off, PGSIZE,
                     (uint64)pa, PTE_R | PTE_W | PTE_U) < 0) {
          kfree(pa); iunlock(f->ip); return -1;
        }

        if (readi(f->ip, 0, (uint64)pa, file_off, chunk) != (int)chunk) {
          // read failed (e.g. empty file) — page is zerod, that's OK
        }

        left -= chunk;
        file_off += chunk;
        mem_off += chunk;
      }
      iunlock(f->ip);
      did_file_map = 1;
    }
  }

  // MAP_ANON or file open failed: allocate zero-filled anonymous pages
  if (!did_file_map && length > 0) {
    uint64 left = PGROUNDUP(length);
    uint64 mem_off = old_sz;
    while (left > 0) {
      char *pa = kalloc();
      if (pa == 0) return -1;
      memset(pa, 0, PGSIZE);
      if (mappages(p->pagetable, mem_off, PGSIZE,
                   (uint64)pa, PTE_R | PTE_W | PTE_U) < 0) {
        kfree(pa);
        return -1;
      }
      mem_off += PGSIZE;
      left -= PGSIZE;
    }
  }

  return old_sz;
}

