// mkdirat(dirfd, path, mode)
uint64 sys_mkdirat(void) {
  char path[MAXPATH];
  argstr(1, path, MAXPATH);
  // ext4: pretend success for pre-created dirs
  extern int ext4_fs;
  if (ext4_fs) return 0;
  begin_op();
  struct inode *ip = create(path, T_DIR, 0, 0);
  end_op();
  if (ip == 0) return -1;
  iunlockput(ip);
  return 0;
}

// unlinkat(dirfd, path, flags)
uint64 sys_unlinkat(void) {
  char path[MAXPATH];
  int flags;
  argstr(1, path, MAXPATH);
  argint(2, &flags);
  extern int ext4_fs;

  // ext4: mark directory entry as deleted by zeroing inode field
  if (ext4_fs) {
    struct inode *dp;
    char name[DIRSIZ];
    uint off;
    if ((dp = nameiparent(path, name)) == 0) return 0; // pretend success
    ilock(dp);
    if (dirlookup(dp, name, &off) == 0) { iunlockput(dp); return 0; }
    // Zero just the inode (4 bytes) in the directory entry
    uint zero = 0;
    writei(dp, 0, (uint64)&zero, off, 4);
    iunlockput(dp);
    return 0;
  }

  // xv6 unlink logic
  struct inode *ip, *dp;
  struct dirent de;
  char name[DIRSIZ];
  uint off;

  begin_op();
  if ((dp = nameiparent(path, name)) == 0) { end_op(); return -1; }
  ilock(dp);
  if (namecmp(name, ".") == 0 || namecmp(name, "..") == 0) goto bad_unlink;
  if ((ip = dirlookup(dp, name, &off)) == 0) goto bad_unlink;
  ilock(ip);
  if (ip->nlink < 1) panic("unlink: nlink < 1");
  if (ip->type == T_DIR && !isdirempty(ip)) { iunlockput(ip); goto bad_unlink; }
  memset(&de, 0, sizeof(de));
  if (writei(dp, 0, (uint64)&de, off, sizeof(de)) != sizeof(de)) panic("unlink: writei");
  if (ip->type == T_DIR) { dp->nlink--; iupdate(dp); }
  iunlockput(dp);
  ip->nlink--; iupdate(ip); iunlockput(ip);
  end_op();
  return 0;

bad_unlink:
  iunlockput(dp);
  end_op();
  return -1;
}

// nanosleep(req, rem)
uint64 sys_nanosleep(void) {
  uint64 req_ptr;
  argaddr(0, &req_ptr);
  if (req_ptr == 0) return -1;

  struct { uint64 sec; uint64 nsec; } ts;
  if (copyin(myproc()->pagetable, (char*)&ts, req_ptr, sizeof(ts)) < 0)
    return -1;

  // 10 ticks/sec = 0.1s per tick = 100,000,000 ns
  uint64 ticks_needed = ts.sec * 10 + ts.nsec / 100000000;
  if (ticks_needed == 0 && ts.nsec > 0) ticks_needed = 1;

  acquire(&tickslock);
  uint64 ticks0 = ticks;
  while (ticks - ticks0 < ticks_needed) {
    if (killed(myproc())) { release(&tickslock); return -1; }
    sleep(&ticks, &tickslock);
  }
  release(&tickslock);
  return 0;
}

// gettimeofday(tv, tz) — return current time from ticks counter
uint64 sys_gettimeofday(void) {
  uint64 tv_ptr;
  argaddr(0, &tv_ptr);
  if (tv_ptr == 0) return -1;
  struct { uint64 sec; uint64 usec; } tv;
  acquire(&tickslock);
  tv.sec = ticks / 10;           // 10 ticks/sec
  tv.usec = (ticks % 10) * 100000; // remainder in microseconds
  release(&tickslock);
  if (copyout(myproc()->pagetable, tv_ptr, (char*)&tv, sizeof(tv)) < 0)
    return -1;
  return 0;
}

