// Free an ext4 block in the bitmap.
void
ext4_bfree(uint dev, uint ext4_pblk)
{
  extern uint ext4_blocks_per_group;
  extern struct ext4_superblock ext4_sb;
  uint first_data = ext4_sb.first_data_block;
  uint group = (ext4_pblk - first_data) / ext4_blocks_per_group;
  uint bmap_blk = ext4_gdt[group].block_bitmap;
  uint bit = (ext4_pblk - first_data) % ext4_blocks_per_group;
  uint byte_off = bit / 8;
  uint bit_off = bit % 8;
  uint sector = bmap_blk * ext4_sectors_per_block + byte_off / BSIZE;
  uint byte_in_sector = byte_off % BSIZE;

  struct buf *bp = bread(dev, sector);
  bp->data[byte_in_sector] &= ~(1 << bit_off);
  bwrite(bp);
  brelse(bp);
}

// Allocate an ext4 inode. Returns inode number, 0 = fail.
uint
ext4_ialloc(uint dev)
{
  extern uint ext4_inodes_per_group;
  extern uint ext4_blocks_per_group;
  extern struct ext4_superblock ext4_sb;
  uint ngroups = (ext4_sb.blocks_count - ext4_sb.first_data_block
                  + ext4_blocks_per_group - 1) / ext4_blocks_per_group;

  for (uint g = 0; g < ngroups; g++) {
    uint free_inodes = le16_to_host(ext4_gdt[g].free_inodes_count);
    if (free_inodes == 0) continue;

    uint imap_blk = ext4_gdt[g].inode_bitmap;
    uint first_ino = g * ext4_inodes_per_group + 1;
    uint last_ino = first_ino + ext4_inodes_per_group - 1;
    if (last_ino > ext4_sb.inodes_count) last_ino = ext4_sb.inodes_count;

    for (uint ino = first_ino; ino <= last_ino; ino++) {
      uint bit = ino - 1 - g * ext4_inodes_per_group;
      uint byte_off = bit / 8;
      uint bit_off = bit % 8;
      uint sector = imap_blk * ext4_sectors_per_block + byte_off / BSIZE;
      uint byte_in_sector = byte_off % BSIZE;

      struct buf *bp = bread(dev, sector);
      if ((bp->data[byte_in_sector] & (1 << bit_off)) == 0) {
        bp->data[byte_in_sector] |= (1 << bit_off);
        bwrite(bp);
        brelse(bp);
        // Initialize the inode to a minimal valid state
        struct ext4_inode *raw;
        struct buf *ip_bp = ext4_read_inode_buf(dev, ino, &raw);
        memset(raw, 0, sizeof(struct ext4_inode));
        le16_store(raw->mode, 0x81A4); // default file mode
        le32_store(raw->flags, 0x80000); // EXT4_EXTENTS_FL
        le16_store(raw->links_count, 1);
        // Set times to 0 (acceptable)
        bwrite(ip_bp);
        brelse(ip_bp);
        return ino;
      }
      brelse(bp);
    }
  }
  printf("ext4_ialloc: no inodes\n");
  return 0;
}

// Add an ext4 directory entry.
int
ext4_dirlink(struct inode *dp, char *name, uint inum, uchar file_type)
{
  uint namelen = strlen(name);
  if (namelen > 255) return -1;

  // Calculate rec_len (aligned to 4 bytes)
  uint reclen = 8 + namelen;
  if (reclen & 3) reclen += 4 - (reclen & 3);

  // Scan directory for empty slot or space to split
  uint off = 0;
  uint last_off = 0;
  uint last_reclen = 0;
  uchar entry[256];

  while (off < dp->size) {
    struct ext4_dir_entry de;
    if (readi(dp, 0, (uint64)&de, off, 8) != 8) break;
    uint existing_reclen = le16_to_host((uchar*)&de.rec_len);
    uint existing_inode  = le32_to_host((uchar*)&de.inode);
    // Check for empty entry with enough space
    if (existing_inode == 0 && existing_reclen >= reclen)
      goto write_entry;
    last_off = off;
    last_reclen = existing_reclen;
    off += existing_reclen;
  }

  // If we reached past dp->size, there's room within the last entry's rec_len
  if (off > dp->size && last_reclen >= reclen + 8) {
    // Reduce the last entry's rec_len to its minimum
    // Read the last entry to find its actual name length
    struct ext4_dir_entry de;
    if (readi(dp, 0, (uint64)&de, last_off, 8) == 8) {
      uint last_namelen = de.name_len;
      uint min_rec = 8 + last_namelen;
      if (min_rec & 3) min_rec += 4 - (min_rec & 3);
      // Write back with reduced rec_len
      uchar tmp[8];
      memmove(tmp, (uchar*)&de, 8);
      le16_store(tmp + 4, min_rec);
      if (writei(dp, 0, (uint64)tmp, last_off, 8) != 8) return -1;
      // New entry goes right after
      off = last_off + min_rec;
      goto write_entry;
    }
  }

  // Need to extend directory: allocate a new block
  {
    uint new_block = ext4_bmap_alloc(dp, off / BSIZE);
    if (new_block == 0) return -1;
  }
  dp->size = off;

write_entry:
  memset(entry, 0, sizeof(entry));
  le32_store(entry, inum);
  le16_store(entry + 4, reclen);
  entry[6] = namelen;
  entry[7] = file_type;
  memmove(entry + 8, name, namelen);

  if (writei(dp, 0, (uint64)entry, off, reclen) != reclen)
    return -1;
  return 0;
}

// Remove an ext4 directory entry by name.
int
ext4_dirremove(struct inode *dp, char *name)
{
  uint off = 0;
  while (off < dp->size) {
    struct ext4_dir_entry de;
    if (readi(dp, 0, (uint64)&de, off, 8) != 8) break;
    uint reclen = le16_to_host((uchar*)&de.rec_len);
    uint inode  = le32_to_host((uchar*)&de.inode);
    uchar name_len = de.name_len;

    if (inode != 0 && name_len == strlen(name) &&
        memcmp(de.name, name, name_len) == 0) {
      // Mark entry as empty
      uchar zero[4] = {0,0,0,0};
      if (writei(dp, 0, (uint64)zero, off, 4) != 4) return -1;
      return 0;
    }
    off += reclen;
  }
  return -1;
}

// Truncate (free all blocks) of an ext4 inode.
void
ext4_itrunc(struct inode *ip)
{
  // For simplicity, just clear the extent tree root and reset size.
  // Blocks are leaked (not freed) — acceptable for test workloads.
  uint dev = ip->dev;
  struct ext4_inode *raw;
  struct buf *bp = ext4_read_inode_buf(dev, ip->inum, &raw);

  // Read all extents and free the blocks
  struct ext4_extent_header *eh = (struct ext4_extent_header *)raw->block;
  ushort magic = le16_to_host(eh->magic);
  if (magic == EXT4_EXT_MAGIC && le16_to_host(eh->depth) == 0) {
    ushort entries = le16_to_host(eh->entries);
    struct ext4_extent *exts = (struct ext4_extent *)(eh + 1);
    for (int i = 0; i < entries; i++) {
      uint start = le32_to_host(exts[i].start_lo)
                 | ((uint)le16_to_host(exts[i].start_hi) << 16);
      ushort len = le16_to_host(exts[i].len) & 0x7FFF;
      for (ushort j = 0; j < len; j++)
        ext4_bfree(dev, start + j);
    }
  }

  // Clear extent tree
  memset(raw->block, 0, 60);
  le32_store(raw->size_lo, 0);
  le32_store(raw->size_hi, 0);
  bwrite(bp);
  brelse(bp);
}

    iupdate(dp);
  }

  iunlockput(dp);

  return ip;

fail:
  // something went wrong. de-allocate ip.
  ip->nlink = 0;
  iupdate(ip);
  iunlockput(ip);
  iunlockput(dp);
  return 0;
}

uint64
sys_open(void)
{
  char path[MAXPATH];
  int fd, omode;
  struct file *f;
  struct inode *ip;
  int n;

  argint(1, &omode);
  if ((n = argstr(0, path, MAXPATH)) < 0)
    return -1;

  begin_op();

  if (omode & O_CREATE) {
    ip = create(path, T_FILE, 0, 0);
    if (ip == 0) {
      end_op();
      return -1;
    }
  } else {
    if ((ip = namei(path)) == 0) {
      end_op();
      return -1;
    }
    ilock(ip);
    {
      int accmode = omode & 0x3;
      if (ip->type == T_DIR && accmode != O_RDONLY) {
        iunlockput(ip); end_op(); return -1;
      }
    }
  }

  if (ip->type == T_DEVICE && (ip->major < 0 || ip->major >= NDEV)) {
    iunlockput(ip);
    end_op();
    return -1;
  }

  if ((f = filealloc()) == 0 || (fd = fdalloc(f)) < 0) {
    if (f)
      fileclose(f);
    iunlockput(ip);
    end_op();
    return -1;
  }

  if (ip->type == T_DEVICE) {
    f->type = FD_DEVICE;
    f->major = ip->major;
  } else {
    f->type = FD_INODE;
    f->off = 0;
  }
  f->ip = ip;
  f->readable = !(omode & O_WRONLY);
  f->writable = (omode & O_WRONLY) || (omode & O_RDWR);

  if ((omode & O_TRUNC) && ip->type == T_FILE) {
    itrunc(ip);
  }

  iunlock(ip);
  end_op();

  return fd;
}

