  }


  // Copy user memory from parent to child.
  if (uvmcopy(p->pagetable, np->pagetable, p->sz) < 0) {
    freeproc(np);
    release(&np->lock);
    return -1;
  }
  np->sz = p->sz;


  memset(np->trapframe, 0, sizeof(struct trapframe)); // 清零！
  *(np->trapframe) = *(p->trapframe);                // 再复制！

  // Cause fork to return 0 in the child.
  np->trapframe->a0 = 0;
  // For clone(): set child's stack pointer if requested
  if (child_sp != 0) {
    np->trapframe->sp = child_sp;
  }

  // increment reference counts on open file descriptors.
  for (i = 0; i < NOFILE; i++)
    if (p->ofile[i])
      np->ofile[i] = filedup(p->ofile[i]);
  np->cwd = idup(p->cwd);

  safestrcpy(np->name, p->name, sizeof(p->name));
  safestrcpy(np->contest_path, p->contest_path, sizeof(np->contest_path));
  safestrcpy(np->contest_argv1, p->contest_argv1, sizeof(np->contest_argv1));
  safestrcpy(np->contest_argv2, p->contest_argv2, sizeof(np->contest_argv2));
  np->brk = p->brk;

  pid = np->pid;

  release(&np->lock);

  acquire(&wait_lock);
  np->parent = p;
  release(&wait_lock);

  acquire(&np->lock);
  np->state = RUNNABLE;
  release(&np->lock);

  return pid;
}

// Pass p's abandoned children to init.
// Caller must hold wait_lock.
void
reparent(struct proc *p)
{

  sched();
  release(&p->lock);
}

// A fork child's very first scheduling by scheduler()
// will swtch to forkret.
void
forkret(void)
{
  extern char userret[];
  static int first = 1;
  struct proc *p = myproc();

  // Still holding p->lock from scheduler.
  release(&p->lock);

  if (first) {
    // File system initialization must be run in the context of a
    // regular process (e.g., because it calls sleep), and thus cannot
    // be run from main().
    fsinit(ROOTDEV);

    first = 0;
    // ensure other cores see first=0.
    __atomic_thread_fence(__ATOMIC_SEQ_CST);

    // We can invoke kexec() now that file system is initialized.
    // Put the return value (argc) of kexec into a0.
    extern int ext4_fs;
    if (ext4_fs) {
      p->trapframe->a0 = contest_exec_first();
    } else {
      p->trapframe->a0 = kexec("/init", (char *[]){"/init", 0});
    }
    if (p->trapframe->a0 == -1) {
      printf("kexec failed, shutting down\n");
      // SBI shutdown
      register long a0 asm("a0") = 0;
      register long a6 asm("a6") = 0;
      register long a7 asm("a7") = 0x53525354;
      asm volatile("ecall" : "+r"(a0) : "r"(a6), "r"(a7) : "memory");
    }
  } else if (p->contest_path[0]) {
    p->contest_ticks = 0;
    char exec_path[MAXPATH];
    safestrcpy(exec_path, p->contest_path, sizeof(exec_path));
    p->contest_path[0] = 0;

    // chdir to test's directory so relative paths (./text.txt) work
    char dir[MAXPATH];
    safestrcpy(dir, exec_path, sizeof(dir));
    char *s;
    for (s = dir + strlen(dir); s >= dir && *s != '/'; s--) ;
    if (s >= dir) *s = 0;  // strip filename, leave directory path
    struct inode *newcwd = namei(dir[0] ? dir : "/");
    if (newcwd) {
      ilock(newcwd);
      if (newcwd->type == T_DIR) { iput(p->cwd); p->cwd = newcwd; iunlock(newcwd); }
      else { iunlockput(newcwd); }
    }

    // Build argv: T2025-style ["/path/busybox", "sh", "script", NULL]
    char *argv[MAXARG];
    memset(argv, 0, sizeof(argv));
    argv[0] = exec_path;  // full busybox path (e.g. /musl/busybox)
    int argc = 1;
    char extra1[256], extra2[256];
    if (p->contest_argv1[0]) {
      safestrcpy(extra1, p->contest_argv1, sizeof(extra1));
      p->contest_argv1[0] = 0;
      argv[argc++] = extra1;  // argv[1] = applet name (e.g. "sh")
      if (p->contest_argv2[0]) {
        safestrcpy(extra2, p->contest_argv2, sizeof(extra2));
        p->contest_argv2[0] = 0;
        argv[argc++] = extra2;  // argv[2] = script path
      }
    }
    argv[argc] = 0;

    int r = kexec(exec_path, argv);
    if (r < 0) {
      //printf("[forkret] pid=%d kexec FAILED for %s\n", p->pid, exec_path);
      kexit(1);
    }
  }
  // return to user space, mimicing usertrap()'s return.
  prepare_return();
  uint64 satp = MAKE_SATP(p->pagetable);
  uint64 trampoline_userret = TRAMPOLINE + (userret - trampoline);
  ((void (*)(uint64))trampoline_userret)(satp);
}
